{"command": "cat <<'EOF' > fix_extract_lane.cpp
// Fixed implementation of ExtractLane
Value *VPInstruction::generate(VPTransformState &State) {
  case VPInstruction::ExtractLane: {
    Value *LaneToExtract = State.get(getOperand(0), true);
    Type *IdxTy = State.TypeAnalysis.inferScalarType(getOperand(0));
    Value *Res = nullptr;
    Value *RuntimeVF = getRuntimeVF(State.Builder, IdxTy, State.VF);

    for (unsigned Idx = 1; Idx != getNumOperands(); ++Idx) {
      Value *VectorStart =
          Builder.CreateMul(RuntimeVF, ConstantInt::get(IdxTy, Idx - 1));

      // Check if lane is in current part's range
      Value *VectorEnd = Builder.CreateAdd(VectorStart, RuntimeVF);
      Value *InCurrentPart = Builder.CreateAnd(
          Builder.CreateICmpUGE(LaneToExtract, VectorStart),
          Builder.CreateICmpULT(LaneToExtract, VectorEnd));

      if (State.VF.isScalar()) {
        // In scalar mode, each operand is a scalar value
        Value *ScalarVal = State.get(getOperand(Idx));
        if (Res) {
          Res = Builder.CreateSelect(InCurrentPart, ScalarVal, Res);
        } else {
          Res = ScalarVal;
        }
      } else {
        // In vector mode, compute index within current part
        Value *VectorIdx = Builder.CreateSub(LaneToExtract, VectorStart);
        Value *Ext = Builder.CreateExtractElement(
            State.get(getOperand(Idx)), VectorIdx);

        if (Res) {
          Res = Builder.CreateSelect(InCurrentPart, Ext, Res);
        } else {
          Res = Ext;
        }
      }
    }
    return Res;
  }
}
