{"command": "cat <<'EOF' > correct_extract_lane3.cpp
// Correct implementation of ExtractLane
Value *VPInstruction::generate(VPTransformState &State) {
  case VPInstruction::ExtractLane: {
    Value *LaneToExtract = State.get(getOperand(0), true);
    Type *IdxTy = State.TypeAnalysis.inferScalarType(getOperand(0));
    Value *Res = PoisonValue::get(inferScalarType(this));
    Value *RuntimeVF = getRuntimeVF(State.Builder, IdxTy, State.VF);

    // We need to handle the case where LaneToExtract might be out of range
    // of all parts. This can happen if FirstActiveLane returns -1 (no active lanes).
    // But FirstActiveLane should return a valid index if there's an early exit.

    for (unsigned Idx = 1; Idx != getNumOperands(); ++Idx) {
      Value *VectorStart =
          Builder.CreateMul(RuntimeVF, ConstantInt::get(IdxTy, Idx - 1));

      if (State.VF.isScalar()) {
        // In scalar mode, each operand is a scalar value
        Value *ScalarVal = State.get(getOperand(Idx));
        // Check if lane is in current part (which is just 1 element in scalar mode)
        Value *InCurrentPart = Builder.CreateICmpEQ(LaneToExtract, VectorStart);
        Res = Builder.CreateSelect(InCurrentPart, ScalarVal, Res);
      } else {
        // In vector mode
        // Check if lane is in current part: VectorStart <= LaneToExtract < VectorStart + RuntimeVF
        Value *InCurrentPart = Builder.CreateAnd(
            Builder.CreateICmpUGE(LaneToExtract, VectorStart),
            Builder.CreateICmpULT(LaneToExtract, 
                Builder.CreateAdd(VectorStart, RuntimeVF)));

        // Only compute extract if needed
        BasicBlock *CurrentBB = Builder.GetInsertBlock();
        BasicBlock *ThenBB = CurrentBB->splitBasicBlock(Builder.GetInsertPoint(), "extract.then");
        BasicBlock *MergeBB = ThenBB->splitBasicBlock(ThenBB->getFirstNonPHI(), "extract.merge");

        // Replace the unconditional branch with conditional
        CurrentBB->getTerminator()->eraseFromParent();
        Builder.SetInsertPoint(CurrentBB);
        Builder.CreateCondBr(InCurrentPart, ThenBB, MergeBB);

        // Then block: compute extract
        Builder.SetInsertPoint(ThenBB);
        Value *VectorIdx = Builder.CreateSub(LaneToExtract, VectorStart);
        Value *Ext = Builder.CreateExtractElement(
            State.get(getOperand(Idx)), VectorIdx);
        Builder.CreateBr(MergeBB);

        // Merge block: phi node
        Builder.SetInsertPoint(MergeBB->getFirstNonPHI());
        PHINode *Phi = Builder.CreatePHI(inferScalarType(this), 2);
        Phi->addIncoming(Res, CurrentBB);
        Phi->addIncoming(Ext, ThenBB);
        Res = Phi;
      }
    }
    return Res;
  }
}
EOF"}

